{
  "description": "WCAG 2.2 rules reference for design_audit tool. Covers Level A, AA, and AAA criteria relevant to UI design.",
  "contrast-ratios": {
    "AA": {
      "normal-text": {
        "min_ratio": 4.5,
        "description": "Text smaller than 18pt (24px) or 14pt bold (18.67px)"
      },
      "large-text": {
        "min_ratio": 3.0,
        "description": "Text 18pt+ (24px+) or 14pt+ bold (18.67px+)"
      },
      "ui-components": {
        "min_ratio": 3.0,
        "description": "Active UI components and meaningful graphics"
      },
      "focus-indicator": {
        "min_ratio": 3.0,
        "description": "Focus indicators against adjacent colors"
      }
    },
    "AAA": {
      "normal-text": {
        "min_ratio": 7.0,
        "description": "Enhanced contrast for body text"
      },
      "large-text": {
        "min_ratio": 4.5,
        "description": "Enhanced contrast for large text"
      }
    }
  },
  "success-criteria": {
    "1.1.1": {
      "name": "Non-text Content",
      "level": "A",
      "design_impact": "All images need alt text, decorative images need empty alt",
      "checklist": [
        "Images have descriptive alt text",
        "Decorative images use alt=''",
        "Complex images have long description",
        "Icon buttons have accessible name"
      ]
    },
    "1.3.1": {
      "name": "Info and Relationships",
      "level": "A",
      "design_impact": "Visual hierarchy must be programmatically determinable",
      "checklist": [
        "Headings use proper h1-h6 hierarchy",
        "Lists use proper list markup",
        "Tables have headers",
        "Form fields have labels"
      ]
    },
    "1.3.4": {
      "name": "Orientation",
      "level": "AA",
      "design_impact": "Content must work in both portrait and landscape",
      "checklist": [
        "No orientation lock unless essential",
        "Content reflows for both orientations"
      ]
    },
    "1.4.1": {
      "name": "Use of Color",
      "level": "A",
      "design_impact": "Color cannot be the only means of conveying information",
      "checklist": [
        "Error states use icon + color + text",
        "Links distinguishable without color",
        "Charts use patterns + color"
      ]
    },
    "1.4.3": {
      "name": "Contrast (Minimum)",
      "level": "AA",
      "design_impact": "Text must meet 4.5:1 (normal) or 3:1 (large)",
      "checklist": [
        "Body text \u2265 4.5:1",
        "Large text \u2265 3:1",
        "Placeholder text meets ratio",
        "Disabled elements exempt"
      ]
    },
    "1.4.11": {
      "name": "Non-text Contrast",
      "level": "AA",
      "design_impact": "UI components and graphics need 3:1 against adjacent",
      "checklist": [
        "Buttons borders/fills \u2265 3:1",
        "Input borders \u2265 3:1",
        "Icons \u2265 3:1",
        "Focus rings \u2265 3:1"
      ]
    },
    "1.4.12": {
      "name": "Text Spacing",
      "level": "AA",
      "design_impact": "Content must be readable with user-adjusted spacing",
      "checklist": [
        "Line height \u2265 1.5x font size",
        "Paragraph spacing \u2265 2x font size",
        "Letter spacing \u2265 0.12x font size",
        "Word spacing \u2265 0.16x font size"
      ]
    },
    "1.4.13": {
      "name": "Content on Hover or Focus",
      "level": "AA",
      "design_impact": "Tooltips/popovers must be dismissible, hoverable, persistent",
      "checklist": [
        "Dismissible (Esc key)",
        "Hoverable (mouse can enter tooltip)",
        "Persistent (stays until dismissed)"
      ]
    },
    "2.1.1": {
      "name": "Keyboard",
      "level": "A",
      "design_impact": "All functionality available via keyboard",
      "checklist": [
        "All interactive elements focusable",
        "Custom widgets have keyboard support",
        "No keyboard traps",
        "Logical tab order"
      ]
    },
    "2.4.7": {
      "name": "Focus Visible",
      "level": "AA",
      "design_impact": "Focus indicator must be clearly visible",
      "checklist": [
        "Focus ring \u2265 2px",
        "Focus ring contrast \u2265 3:1",
        "Focus visible on all interactive elements",
        "Custom focus styles don't reduce visibility"
      ]
    },
    "2.4.11": {
      "name": "Focus Not Obscured (Minimum)",
      "level": "AA",
      "design_impact": "Focused element not entirely hidden by other content",
      "checklist": [
        "Sticky headers don't cover focused elements",
        "Modals manage focus properly",
        "Scroll position reveals focused element"
      ]
    },
    "2.5.8": {
      "name": "Target Size (Minimum)",
      "level": "AA",
      "design_impact": "Touch targets minimum 24x24px",
      "checklist": [
        "Buttons \u2265 24x24px",
        "Links in text exempt",
        "Inline targets have spacing",
        "Recommended: 44x44px for mobile"
      ]
    },
    "3.2.6": {
      "name": "Consistent Help",
      "level": "A",
      "design_impact": "Help mechanisms in consistent location across pages",
      "checklist": [
        "Help link in consistent position",
        "Contact info consistent",
        "FAQ accessible from all pages"
      ]
    },
    "3.3.1": {
      "name": "Error Identification",
      "level": "A",
      "design_impact": "Errors clearly identified and described in text",
      "checklist": [
        "Error messages in text (not just color)",
        "Error associated with field",
        "Error describes what went wrong",
        "Suggestion for correction"
      ]
    },
    "3.3.2": {
      "name": "Labels or Instructions",
      "level": "A",
      "design_impact": "Form inputs have visible labels",
      "checklist": [
        "All inputs have visible labels",
        "Required fields indicated",
        "Format hints provided",
        "Labels don't disappear on focus"
      ]
