{
  "$schema": "https://design-tokens.github.io/community-group/format/",
  "description": "W3C DTCG design token template. Source of truth format for all token generation.",
  "template": {
    "color": {
      "primary": {
        "$value": "#ec7d1a",
        "$type": "color",
        "$description": "Primary brand color"
      },
      "on-primary": {
        "$value": "#ffffff",
        "$type": "color",
        "$description": "Text/icon color on primary"
      }
    },
    "typography": {
      "font-family": {
        "heading": {
          "$value": "'Plus Jakarta Sans', system-ui, sans-serif",
          "$type": "fontFamily"
        },
        "body": {
          "$value": "'Inter', system-ui, sans-serif",
          "$type": "fontFamily"
        },
        "mono": {
          "$value": "'Fira Code', ui-monospace, monospace",
          "$type": "fontFamily"
        }
      },
      "font-size": {
        "base": {
          "$value": "16px",
          "$type": "dimension"
        },
        "lg": {
          "$value": "20px",
          "$type": "dimension"
        }
      },
      "font-weight": {
        "regular": {
          "$value": 400,
          "$type": "fontWeight"
        },
        "medium": {
          "$value": 500,
          "$type": "fontWeight"
        },
        "semibold": {
          "$value": 600,
          "$type": "fontWeight"
        },
        "bold": {
          "$value": 700,
          "$type": "fontWeight"
        }
      },
      "line-height": {
        "tight": {
          "$value": 1.2,
          "$type": "number"
        },
        "normal": {
          "$value": 1.5,
          "$type": "number"
        },
        "relaxed": {
          "$value": 1.7,
          "$type": "number"
        }
      }
    },
    "spacing": {
      "1": {
        "$value": "4px",
        "$type": "dimension"
      },
      "2": {
        "$value": "8px",
        "$type": "dimension"
      },
      "3": {
        "$value": "12px",
        "$type": "dimension"
      },
      "4": {
        "$value": "16px",
        "$type": "dimension"
      }
    },
    "border-radius": {
      "sm": {
        "$value": "4px",
        "$type": "dimension"
      },
      "md": {
        "$value": "8px",
        "$type": "dimension"
      },
      "lg": {
        "$value": "12px",
        "$type": "dimension"
      },
      "xl": {
        "$value": "16px",
        "$type": "dimension"
      }
    },
    "shadow": {
      "sm": {
        "$value": {
          "color": "rgba(0,0,0,0.05)",
          "offsetX": "0px",
          "offsetY": "1px",
          "blur": "3px",
          "spread": "0px"
        },
        "$type": "shadow"
      }
    },
    "duration": {
      "fast": {
        "$value": "150ms",
        "$type": "duration"
      },
      "normal": {
        "$value": "250ms",
        "$type": "duration"
      },
      "slow": {
        "$value": "400ms",
        "$type": "duration"
      }
    }
  },
  "export-formats": {
    "css": {
      "description": "CSS custom properties",
      "example": ":root {\n  --color-primary: #ec7d1a;\n  --font-size-base: 1rem;\n  --spacing-4: 1rem;\n}",
      "naming": "kebab-case"
    },
    "tailwind": {
      "description": "Tailwind CSS theme config",
      "example": "module.exports = {\n  theme: {\n    extend: {\n      colors: { primary: '#ec7d1a' },\n      fontSize: { base: '1rem' }\n    }\n  }\n}",
      "naming": "kebab-case"
    },
    "scss": {
      "description": "SCSS variables",
      "example": "$color-primary: #ec7d1a;\n$font-size-base: 1rem;\n$spacing-4: 1rem;",
      "naming": "kebab-case"
    },
    "js": {
      "description": "JavaScript/TypeScript module export",
      "example": "export const tokens = {\n  colorPrimary: '#ec7d1a',\n  fontSizeBase: '1rem',\n  spacing4: '1rem'\n} as const;",
      "naming": "camelCase"
    }
  }
}
